const loadFonts = async (pdfDoc) =>{
  
	var TimesRomanBold = await pdfDoc.embedFont(StandardFonts.TimesRomanBold);


  let fontUrl = getStore("Roboto-Bold.ttf");
  const fontBytes =  await fetch(fontUrl).then((res) => res.arrayBuffer());
  const RobotoBold = await pdfDoc.embedFont(fontBytes, { subset: true });



  let fontUrlRoboto_italic = getStore("ggSans-Medium.ttf");
  const fontBytes2 =  await fetch(fontUrlRoboto_italic).then((res) => res.arrayBuffer());
  const GSansBold = await pdfDoc.embedFont(fontBytes2,{ subset: true });


  let fontUrlGSB = getStore("Roboto-Regular.ttf");
  const fontBytes_GSB =  await fetch(fontUrlGSB).then((res) => res.arrayBuffer());
  const RobotoRegular = await pdfDoc.embedFont(fontBytes_GSB, { subset: true });


  let fontUrlariaR = getStore("arial_bold.ttf");;
  const fbAr =  await fetch(fontUrlariaR).then((res) => res.arrayBuffer());
  let ariaRegular = await pdfDoc.embedFont(fbAr,{ subset: true });


   
  return {
    "GSansBold":GSansBold,
    "RobotoRegular":RobotoRegular,
    "RobotoBold":RobotoBold,
    "ariaRegular": ariaRegular,
    "TimesRomanBold":TimesRomanBold
  }

}





export const ShipLabels2LogisticPdf = async (list, blob, certify) => {
    
  

	const pdfDoc = await PDFDocument.create() 
	pdfDoc.registerFontkit(fontkit);


   
  let fonstP = await loadFonts(pdfDoc);

  let ww =260;

	const promises = list.map(async (item, ind2) => {
			const page = pdfDoc.addPage([284, 162]);
			const { width, height } = page.getSize();
			let heightPg = height - 30;
    
		
      let leftX = 30;

      let stateFsz = Math.floor( ww / item?.state.length * 2.02);
      if(stateFsz>42){
        stateFsz = 42;
        heightPg = heightPg - 6;
      }
         
      let nameFsz = Math.floor( ww / item?.name.length * 2.02);
       
        if(item?.state){
          const stateWidth = fonstP.RobotoBold.widthOfTextAtSize(txtOrempty(item?.state) , stateFsz);
          page.drawText( txtOrempty(item?.state), {
            x: 140 - (stateWidth / 2) ,
            y:  heightPg,
            size: stateFsz,
            font: fonstP.RobotoBold,
            color:  rgb(0, 0, 0),
          })
          heightPg = heightPg -nameFsz - 10;
        }

       
        const nameWidth =  fonstP.GSansBold.widthOfTextAtSize(txtOrempty(item?.name) , nameFsz);
        page.drawText( txtOrempty(item?.name), {
          x: 270 - nameWidth,
          y:  heightPg,
          size: nameFsz,
          font: fonstP.GSansBold,
          color:  rgb(0, 0, 0),
        })

        nameFsz = nameFsz<24? 30: nameFsz;
        const phoneNumberWidth = fonstP.GSansBold.widthOfTextAtSize(txtOrempty(item?.phoneNumber) , 32);
        page.drawText( txtOrempty(item?.phoneNumber), {
          x: 270 - phoneNumberWidth,
          y:  heightPg- nameFsz -8,
          size: 32,
          font: fonstP.GSansBold,
          color:  rgb(0, 0, 0),
        })
        
        const phoneNumberAWidth = fonstP.GSansBold.widthOfTextAtSize(txtOrempty(item?.phoneNumberAlternative) , 32);
        
        page.drawText( txtOrempty(item?.phoneNumberAlternative), {
          x: 270 - phoneNumberAWidth,
          y:  heightPg- nameFsz - 40,
          size: 32,
          font: fonstP.GSansBold,
          color:  rgb(0, 0, 0),
        })
  
        page.drawText( txtOrempty(ind2+1), {
          x: 10,
          y:  5,
          size: 32,
          font: fonstP.RobotoBold,
          color:  rgb(0, 0, 0),
        })

        let url2Qr = "https://rb.gy/culeko/#/order-lookup?o="+item?.orderId+"&p="+item?.packageId;
       
        const pngUrl = getQrcode(txtOrempty(url2Qr));
        const pngImageBytes = await fetch(pngUrl).then((res) => res.arrayBuffer())
        let pngImage = await pdfDoc.embedPng(pngImageBytes);
        pngImage && page.drawImage(pngImage, {
          x: 13,
          y: 31,
          width:  50,
          height: 50,
        })
		
  })
  
 

  const contents = await Promise.all(promises);
  //const contents2 = await Promise.all(promises2);
  if(blob){
    const pdfBytes = await pdfDoc.save();
    return blobfromArray(pdfBytes)
  }
  else{
    return pdfDoc.saveAsBase64({ dataUri: true });
  }



  
	
}
  















